import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/users/login", { email, password });
      
      // ✅ STEP 1: Save User Details to LocalStorage
      localStorage.setItem("token", res.data.token);
      localStorage.setItem("userName", res.data.name); // Backend must send 'name'
      
      alert("Login Successful!");
      navigate('/marketplace');
    } catch (err) {
      alert("Invalid Credentials");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-900 px-4">
      <form onSubmit={handleLogin} className="bg-white p-10 rounded-[2.5rem] shadow-2xl w-full max-w-md">
        <h2 className="text-3xl font-black italic uppercase text-center mb-8">Login <span className="text-red-600">Pro</span></h2>
        <input type="email" placeholder="Email" className="w-full p-4 mb-4 bg-slate-100 rounded-2xl outline-none focus:ring-2 ring-red-500 font-bold" value={email} onChange={e => setEmail(e.target.value)} required />
        <input type="password" placeholder="Password" className="w-full p-4 mb-6 bg-slate-100 rounded-2xl outline-none focus:ring-2 ring-red-500 font-bold" value={password} onChange={e => setPassword(e.target.value)} required />
        <button className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase hover:bg-black transition-all">Enter Dashboard</button>
      </form>
    </div>
  );
}
